export function pickNotFoundQuote(
  isAuthenticated: boolean,
  random: () => number = Math.random,
): NotFoundQuote {
  const pool = isAuthenticated
    ? NOT_FOUND_QUOTES
    : NOT_FOUND_QUOTES.filter((q) => !q.requiresPlayerName);
  return pool[Math.floor(random() * pool.length)]!;
}

export function formatNotFoundQuoteLine(
  quote: NotFoundQuote,
  playerName: string | null | undefined,
): string {
  if (!quote.requiresPlayerName) {
    return quote.line;
  }
  const name = (playerName ?? "adventurer").trim() || "adventurer";
  return quote.line.replace(/\[player name\]/gi, name);
}
